import React, { useState, useEffect } from 'react';
import axios from 'axios';

const InformeFormulario = () => {
  const [data, setData] = useState([]);
  const [headers, setHeaders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Fechas por defecto: Mes y Año Actual
  const hoy = new Date();
  const [selectedMonth, setSelectedMonth] = useState((hoy.getMonth() + 1).toString());
  const [selectedYear, setSelectedYear] = useState(hoy.getFullYear().toString());

  // Generar opciones de años
  const years = [];
  for (let i = 2025; i <= hoy.getFullYear(); i++) {
    years.push(i);
  }

  const mesesInfo = [
    { id: '1', nombre: 'Enero' }, { id: '2', nombre: 'Febrero' }, { id: '3', nombre: 'Marzo' },
    { id: '4', nombre: 'Abril' }, { id: '5', nombre: 'Mayo' }, { id: '6', nombre: 'Junio' },
    { id: '7', nombre: 'Julio' }, { id: '8', nombre: 'Agosto' }, { id: '9', nombre: 'Septiembre' },
    { id: '10', nombre: 'Octubre' }, { id: '11', nombre: 'Noviembre' }, { id: '12', nombre: 'Diciembre' }
  ];

  useEffect(() => {
    fetchData();
  }, [selectedMonth, selectedYear]);

  const fetchData = async () => {
    try {
      setLoading(true);
      setError(null);

      // Calcular primer y último día del mes seleccionado
      const yearInt = parseInt(selectedYear);
      const monthInt = parseInt(selectedMonth);
      const primerDia = new Date(yearInt, monthInt - 1, 1);
      const ultimoDia = new Date(yearInt, monthInt, 0); // 0 obtiene el último día del mes anterior (mes actual en index)

      const formatDate = (date) => {
        const y = date.getFullYear();
        const m = String(date.getMonth() + 1).padStart(2, '0');
        const d = String(date.getDate()).padStart(2, '0');
        return `${y}-${m}-${d}`;
      };

      const startDate = formatDate(primerDia);
      const endDate = formatDate(ultimoDia);

      // Hacemos la petición al nuevo endpoint de reportes externos
      const response = await axios.get('http://localhost/proyectar/api/reportes_externos/read_sheets.php', {
        params: { start_date: startDate, end_date: endDate },
        withCredentials: true
      });

      if (response.data.status === 'success') {
        if (response.data.debug_headers) {
          console.log("🔍 ENCABEZADOS ORIGINALES DE GOOGLE SHEETS:", response.data);
        }
        let sheetData = response.data.data;

        setData(sheetData);
        // Extraer encabezados de la primera fila si hay datos
        if (sheetData.length > 0) {
          setHeaders(Object.keys(sheetData[0]));
        }
      } else {
        setError(response.data.message || 'Error al cargar los datos.');
      }
    } catch (err) {
      console.error("Error fetching sheets data:", err);
      setError(err.response?.data?.message || err.message || 'Error de conexión con el servidor.');
    } finally {
      setLoading(false);
    }
  };

  const exportToExcel = async () => {
    if (!data || data.length === 0) return;

    // Importamos ExcelJS de forma dinámica para manejar imágenes y estilos
    const ExcelJS = (await import('exceljs')).default;
    const mesNombre = mesesInfo.find(m => m.id === selectedMonth)?.nombre || selectedMonth;
    const mesId = mesesInfo.find(m => m.id === selectedMonth)?.id || selectedMonth;

    // --- PEGA TU IMAGEN EN BASE64 AQUÍ ---
    const logoBase64 = "data:image/png;base64,";
    // Ejemplo: "data:image/png;base64,iVBORw..."

    const workbook = new ExcelJS.Workbook();
    const cedulaKey = headers.find(h => h.toUpperCase().includes('CEDULA')) || "CEDULA DEL CONDUCTOR:";

    // Agrupamos por conductor para generar las pestañas
    const groupedData = {};
    data.forEach(row => {
      let cedula = row[cedulaKey] ? row[cedulaKey].toString().trim() : 'Sin_Cedula';
      const safeSheetName = cedula.substring(0, 31).replace(/[\[\]\*\\\/\?]/g, '');
      if (!groupedData[safeSheetName]) groupedData[safeSheetName] = [];
      groupedData[safeSheetName].push(row);
    });

    Object.keys(groupedData).forEach(cedula => {
      const sheetRows = groupedData[cedula];
      const sheet = workbook.addWorksheet(cedula);

      // 1. Configurar anchos de columna
      sheet.columns = [
        { width: 15 }, // A
        { width: 24.3 }, // B (~175px)
        ...Array.from({ length: 31 }, () => ({ width: 3.85 })) // C a AG (31 días ~ 27px)
      ];

      const primerReg = sheetRows[0] || {};
      const conductor = primerReg["NOMBRE DEL CONDUCTOR"] || "-";
      const placaMovil = primerReg["PLACA Y NÚMERO DE MOVIL:"] || "-";
      const placaMovilpartes = placaMovil.split(" - ");

      // --- INFORMACIÓN ADMINISTRATIVA DESDE EL ÚLTIMO REGISTRO (MÁS RECIENTE) ---
      const ultimoReg = sheetRows[sheetRows.length - 1] || {};
      const soatVigente = ultimoReg["SOAT VIGENTE:"] || "-";
      const soatVenc = ultimoReg["FECHA DE VENCIMIENTO DEL SOAT:"] || "-";
      const tecnoVigente = ultimoReg["TECNOMECANICA VIGENTE:"] || "-";
      const tecnoVenc = ultimoReg["FECHA DE VENCIMIENTO DE TECNOMECANICA:"] || "-";
      const kmInicial = ultimoReg["KILOMETRAJE INICIAL:"] || "-";
      const kmAceite = ultimoReg["KILOMETRAJE PARA PROXIMO CAMBIO DE ACEITE:"] || "-";
      const kmCaja = ultimoReg["KILOMETRAJE PARA PROXIMO CAMBIO DE VALVULINA DE CAJA:"] || "-";
      const kmTransmision = ultimoReg["KILOMETRAJE PARA PROXIMO CAMBIO DE VALVULINA DE LA TRANSMISIÓN:"] || "-";

      const parseDateString = (dateStr) => {
        if (!dateStr || dateStr === "-") return { d: "", m: "", y: "" };
        const stringDate = String(dateStr).trim();
        const matchesDate = stringDate.match(/(\d{4})[-/](\d{1,2})[-/](\d{1,2})/) || stringDate.match(/(\d{1,2})[-/](\d{1,2})[-/](\d{4})/);
        if (matchesDate) {
          if (matchesDate[1].length === 4) {
            return { y: matchesDate[1], m: matchesDate[2], d: matchesDate[3] };
          } else {
            return { d: matchesDate[1], m: matchesDate[2], y: matchesDate[3] };
          }
        }
        const d = new Date(stringDate);
        if (!isNaN(d.getTime())) {
          return { d: String(d.getDate()).padStart(2, '0'), m: String(d.getMonth() + 1).padStart(2, '0'), y: String(d.getFullYear()) };
        }
        return { d: "", m: "", y: "" };
      };

      // 2. Definir las 7 filas de encabezado (Celdas A a AG = 33)
      const f1 = Array(33).fill(""); f1[2] = "VEHICULO"; f1[11] = placaMovilpartes[2] || "";
      const f2 = Array(33).fill(""); f2[2] = "No. DE PLACA"; f2[11] = placaMovilpartes[1] || "";
      const f3 = Array(33).fill(""); f3[2] = "No. DE MOVIL"; f3[11] = (placaMovilpartes[0] || "").replace("M-", "# ");
      const f4 = Array(33).fill(""); f4[2] = "CONDUCTOR ASIGNADO"; f4[11] = conductor;
      const f5 = Array(33).fill(""); f5[0] = `MES: (${mesId}) ${mesNombre.toUpperCase()} - ${selectedYear}`; f5[2] = "B: BUENO"; f5[11] = "R: REGULAR"; f5[19] = "M: MALO";
      const f6 = Array(33).fill(""); f6[0] = "VERIFICACION"; f6[2] = "FECHAS EN DIAS";
      const f7 = Array(33).fill("");
      for (let day = 1; day <= 31; day++) f7[day + 1] = day;

      sheet.addRows([f1, f2, f3, f4, f5, f6, f7]);

      // 3. Filas de datos del formulario mapeadas por día
      const configuracionColumnas = [
        { find: "NIVEL DE ACEITE DEL MOTOR", excel: "NIVEL ACEITE" },
        { find: "NIVEL DEL REFRIGERANTE", excel: "NIVEL REFRIGERANTE" },
        { find: "NIVEL DE LIQUIDO DE FRENO", excel: "NIVEL LIQUIDO FRENO" },
        { find: "NIVEL DE AGUA DEL LIMPIA PARA BRISAS", excel: "NIVEL AGUA PARABRISAS" },
        { find: "NIVEL DEL ACEITE HIDRAULICO", excel: "NIVEL ACEITE HIDRAULICO" },
        { find: "ESTADO DE LAS PLUMILLAS", excel: "ESTADO PLUMILLAS" },
        { find: "ESTADO DE LAS LUCES DELANTERAS", excel: "DELANTERAS" },
        { find: "ESTADO DE LAS LUCES TRASERAS", excel: "TRASERAS" },
        { find: "ESTADO DE LAS LUCES LATERALES", excel: "LATERALES" },
        { find: "ESTADO DE LAS LUCES DE BALIZAS", excel: "BALIZAS" },
        { find: "ESTADO DE LAS LUCES INTERMITENTES", excel: "INTERMITENTES" },
        { find: "ESTADO DEL A/C DELANTERO", excel: "A/C DELANTERO" },
        { find: "ESTADO DEL A/C TRASERO", excel: "A/C TRASERO" },
        { find: "ESTADO DE LAS LLANTAS", excel: "ESTADO DE LAS LLANTAS" },
        { find: "FUNCIONAMIENTO DEL SISTEMA DE FRENOS", excel: "FRENOS" },
        { find: "FUNCIONAMIENTO DEL SISTEMA DE DIRECCIÓN", excel: "DIRECCIÓN" },
        { find: "FUNCIONAMIENTO DEL SISTEMA DE SUSPENSIÓN DELANTERA", excel: "SUSPENSIÓN DELANTERA" },
        { find: "FUNCIONAMIENTO DEL SISTEMA DE SUSPENSIÓN TRASERA", excel: "SUSPENSIÓN TRASERA" },
        { find: "ESTADO DEL PARABRISAS", excel: "PARABRISAS" },
        { find: "ESTADO DE LA SIRENA", excel: "SIRENA" },
        { find: "ESTADO DE LOS RETROVISORES", excel: "RETROVISORES" },
        { find: "ESTADO DE LAS MANIJAS DE LAS PUERTAS", excel: "MANIJAS DE LAS PUERTAS" },
        { find: "ESTADO DE LAS PERSIANAS", excel: "PERSIANAS" },
        { find: "ESTADO DE LAS CORREAS DEL MOTOR", excel: "CORREAS DEL MOTOR" },
        { find: "ESTADO DE LOS EXTINTORES", excel: "EXTINTORES" },
        { find: "ESTADO DEL CINTURON DE SEGURIDAD", excel: "CINTURON DE SEGURIDAD" },
        { find: "ESTADO DE LAS LLANTAS DE REPUESTO", excel: "LLANTAS DE REPUESTO" },
        { find: "ESTADO DEL ASEO INTERNO DEL EQUIPO", excel: "INTERNO DEL EQUIPO" },
        { find: "ESTADO DEL ASEO EXTERNO DEL EQUIPO", excel: "EXTERNO DEL EQUIPO" },
        { find: "NIVEL DE COMBUSTIBLE DEL VEHICULO", excel: "NIVEL DE COMBUSTIBLE" },
        { find: "ESTADO DE LA CAMILLA", excel: "CAMILLA" }
      ];

      configuracionColumnas.forEach((colConfig) => {
        const realHeaderKey = headers.find(h => h.toUpperCase().includes(colConfig.find.toUpperCase()));
        const rowValues = Array(33).fill("");
        rowValues[1] = colConfig.excel;

        sheetRows.forEach(rowData => {
          const marca = rowData["Marca temporal"];
          if (marca) {
            const dia = parseInt(marca.split(' ')[0].split('/')[0]);
            if (dia >= 1 && dia <= 31) {
              let valor = "";
              valor = realHeaderKey ? rowData[realHeaderKey] : "";
              // Mapeo compacto solo en Excel (B, R, M)
              if (valor === "BUENO" || valor === "BUEN ESTADO") valor = "B";
              else if (valor === "REGULAR") valor = "R";
              else if (valor === "MALO") valor = "M";

              rowValues[dia + 1] = (valor !== undefined && valor !== "") ? valor : "-";
            }
          }
        });
        sheet.addRow(rowValues);
      });

      const fe1 = Array(33).fill(""); fe1[0] = "ANORMALIDA DEL VEHICULO";
      const fe2 = Array(33).fill(""); fe2[0] = "VERIFICACION"; fe2[2] = "FECHAS EN DIAS";
      const fe3 = Array(33).fill("");
      for (let day = 1; day <= 31; day++) fe3[day + 1] = day;

      sheet.addRows([fe1, fe2, fe3]);

      const configuracionColumnas2 = [
        { find: "¿Percibe ruidos atípicos o inusuales del vehículo?", excel: "RUIDOS ATIPICOS" },
        { find: "¿Recibió el equipó móvil con alguna anomalía", excel: "ANOMALIA ESTRUCTURAL" }
      ];

      configuracionColumnas2.forEach((colConfig) => {
        const realHeaderKey = headers.find(h => h.toUpperCase().includes(colConfig.find.toUpperCase()));
        const rowValues = Array(33).fill("");
        rowValues[1] = colConfig.excel;

        sheetRows.forEach(rowData => {
          const marca = rowData["Marca temporal"];
          if (marca) {
            const dia = parseInt(marca.split(' ')[0].split('/')[0]);
            if (dia >= 1 && dia <= 31) {
              let valor = "";
              valor = realHeaderKey ? rowData[realHeaderKey] : "";

              rowValues[dia + 1] = (valor !== undefined && valor !== "") ? valor : "-";
            }
          }
        });
        sheet.addRow(rowValues);
      });

      const soatFecha = parseDateString(soatVenc);
      const tecnoFecha = parseDateString(tecnoVenc);

      const fe4 = Array(33).fill(""); fe4[0] = "DATOS DEL VEHICULO";
      const fe5 = Array(33).fill(""); fe5[0] = "SOAT"; fe5[2] = "SI"; fe5[3] = (soatVigente == "SI" ? "✔️" : ""); fe5[4] = "NO"; fe5[5] = (soatVigente == "NO" ? "✔️" : ""); fe5[6] = "FECHA DE VENCIMIENTO"; fe5[15] = "DIA"; fe5[18] = soatFecha.d; fe5[21] = "MES"; fe5[24] = soatFecha.m; fe5[27] = "AÑO"; fe5[30] = soatFecha.y;
      const fe6 = Array(33).fill(""); fe6[0] = "TECNOMECANICA"; fe6[2] = "SI"; fe6[3] = (tecnoVigente == "SI" ? "✔️" : ""); fe6[4] = "NO"; fe6[5] = (tecnoVigente == "NO" ? "✔️" : ""); fe6[6] = "FECHA DE VENCIMIENTO"; fe6[15] = "DIA"; fe6[18] = tecnoFecha.d; fe6[21] = "MES"; fe6[24] = tecnoFecha.m; fe6[27] = "AÑO"; fe6[30] = tecnoFecha.y;
      const fe7 = Array(33).fill(""); fe7[0] = "KILOMETRAJE ACTUAL"; fe7[4] = kmInicial; fe7[9] = "KILOMETRAJE PARA PROXIMO CAMBIO DE VALVULINA DE CAJA"; fe7[27] = kmCaja;
      const fe8 = Array(33).fill(""); fe8[0] = "KILOMETRAJE PARA PROXIMO CAMBIO DE ACEITE"; fe8[4] = kmAceite; fe8[9] = "KILOMETRAJE PARA PROXIMO CAMBIO DE VALVULINA DE LA TRANSMISIÓN"; fe8[27] = kmTransmision;


      sheet.addRows([fe4, fe5, fe6, fe7, fe8]);

      // 4. Combinar Celdas y Aplicar Estilos
      sheet.mergeCells('A1:B4'); // Espacio para Logo
      sheet.mergeCells('A5:B5');
      sheet.mergeCells('A6:B7'); // Verificacion
      sheet.mergeCells('C6:AG6'); // Título Fecha
      // Metadata
      sheet.mergeCells('C1:K1'); sheet.mergeCells('L1:AG1');
      sheet.mergeCells('C2:K2'); sheet.mergeCells('L2:AG2');
      sheet.mergeCells('C3:K3'); sheet.mergeCells('L3:AG3');
      sheet.mergeCells('C4:K4'); sheet.mergeCells('L4:AG4');
      // Legend
      sheet.mergeCells('C5:K5'); sheet.mergeCells('L5:S5'); sheet.mergeCells('T5:AG5');


      sheet.mergeCells('A39:AG39');
      sheet.mergeCells('A40:B41');// Verificacion
      sheet.mergeCells('C40:AG40'); // Título Fecha
      sheet.mergeCells('A44:AG44'); // DATOS DEL VEHICULO
      sheet.mergeCells('A45:B45'); sheet.mergeCells('G45:O45'); sheet.mergeCells('P45:R45'); sheet.mergeCells('S45:U45'); sheet.mergeCells('V45:X45'); sheet.mergeCells('Y45:AA45'); sheet.mergeCells('AB45:AD45'); sheet.mergeCells('AE45:AG45'); // SOAT
      sheet.mergeCells('A46:B46'); sheet.mergeCells('G46:O46'); sheet.mergeCells('P46:R46'); sheet.mergeCells('S46:U46'); sheet.mergeCells('V46:X46'); sheet.mergeCells('Y46:AA46'); sheet.mergeCells('AB46:AD46'); sheet.mergeCells('AE46:AG46'); // TECNOMECANICA
      sheet.mergeCells('A47:D47'); sheet.mergeCells('E47:I47'); sheet.mergeCells('J47:AA47'); sheet.mergeCells('AB47:AG47');//KILOMETRAJE F1
      sheet.mergeCells('A48:D48'); sheet.mergeCells('E48:I48'); sheet.mergeCells('J48:AA48'); sheet.mergeCells('AB48:AG48');//KILOMETRAJE F2


      // Aplicar estilos de centrado a los títulos específicos
      ['C5', 'L5', 'T5', 'A6', 'C6', 'A39', 'A40', 'C40', 'A44', 'C45', 'D45', 'E45', 'F45', 'P45', 'S45', 'V45', 'Y45', 'AB45', 'AE45', 'C46', 'D46', 'E46', 'F46', 'P46', 'S46', 'V46', 'Y46', 'AB46', 'AE46', 'E47', 'AB47', 'E48', 'AB48'].forEach(ref => {
        const cell = sheet.getCell(ref);
        cell.alignment = { vertical: 'middle', horizontal: 'center' };
      });

      // Centrar toda la cuadrícula de días (Fila 7 a 40, Columnas C a AG)
      for (let r = 7; r <= 43; r++) {
        const row = sheet.getRow(r);
        for (let c = 3; c <= 33; c++) { // Columna 3 es C, 33 es AG
          const cell = row.getCell(c);
          cell.alignment = { vertical: 'middle', horizontal: 'center' };
        }
      }

      // Insertar Imagen si se proporcionó Base64
      if (logoBase64 && logoBase64.startsWith("data:image")) {
        try {
          const imageId = workbook.addImage({
            base64: logoBase64,
            extension: 'png',
          });
          sheet.addImage(imageId, {
            tl: { col: 0, row: 0 },
            br: { col: 2, row: 4 },
            editAs: 'oneCell'
          });
        } catch (e) {
          console.error("Error al insertar el logo en Excel:", e);
        }
      }
    });

    // --- GENERAR Y DESCARGAR ---
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Reporte_${mesNombre}_${selectedYear}.xlsx`;
    link.click();
    window.URL.revokeObjectURL(url);
  };

  return (
    <div className="container-fluid py-4">
      <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center mb-4 gap-3">
        <div>
          <h2 className="text-primary-institucional mb-0">
            <i className="bi bi-file-earmark-spreadsheet me-2"></i>
            Informe de Formulario Externo
          </h2>
          <p className="text-muted mt-1 mb-0">Datos sincronizados desde Google Sheets</p>
        </div>

        <div className="d-flex align-items-center gap-2 bg-light p-2 rounded border">
          <div className="d-flex align-items-center">
            <label className="text-muted small me-2 mb-0 fw-bold">Mes:</label>
            <select
              className="form-select form-select-sm"
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
            >
              {mesesInfo.map(mes => (
                <option key={mes.id} value={mes.id}>{mes.nombre}</option>
              ))}
            </select>
          </div>
          <div className="d-flex align-items-center">
            <label className="text-muted small me-2 mb-0 fw-bold">Año:</label>
            <select
              className="form-select form-select-sm"
              value={selectedYear}
              onChange={(e) => setSelectedYear(e.target.value)}
            >
              {years.map(year => (
                <option key={year} value={year}>{year}</option>
              ))}
            </select>
          </div>
          <button className="btn btn-primary btn-sm ms-2 d-flex align-items-center" onClick={fetchData} disabled={loading}>
            <i className={`bi bi-arrow-clockwise me-1 ${loading ? 'lh-spin' : ''}`}></i>
            {loading ? 'Cargando..' : 'Filtrar'}
          </button>
          <button
            className="btn btn-success btn-sm ms-2 d-flex align-items-center"
            onClick={exportToExcel}
            disabled={loading || data.length === 0}
            title="Exportar archivo de Excel con hojas por conductor"
          >
            <i className="bi bi-file-earmark-excel me-1"></i>
            Descargar
          </button>
        </div>
      </div>

      {error && (
        <div className="alert alert-danger d-flex align-items-center" role="alert">
          <i className="bi bi-exclamation-triangle-fill flex-shrink-0 me-2"></i>
          <div>{error}</div>
        </div>
      )}

      <div className="card shadow-sm border-0">
        <div className="card-body p-0">
          {loading ? (
            <div className="text-center p-5">
              <div className="spinner-border text-primary-institucional" role="status" style={{ width: '3rem', height: '3rem' }}>
                <span className="visually-hidden">Cargando...</span>
              </div>
              <p className="mt-3 text-muted">Conectando con Google Sheets...</p>
            </div>
          ) : data.length === 0 && !error ? (
            <div className="text-center p-5">
              <i className="bi bi-inbox text-muted" style={{ fontSize: '3rem' }}></i>
              <h5 className="mt-3 text-muted">No se encontraron datos</h5>
              <p className="text-muted mb-0">La hoja de cálculo seleccionada está vacía o no tiene el formato esperado.</p>
            </div>
          ) : data.length > 0 ? (
            <div className="table-responsive">
              <table className="table table-hover table-bordered mb-0 align-middle">
                <thead className="table-light">
                  <tr>
                    <th scope="col" className="text-center" style={{ width: '50px' }}>#</th>
                    {headers.map((header, index) => (
                      <th scope="col" key={index} className="text-nowrap">{header}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {data.map((row, rowIndex) => (
                    <tr key={rowIndex}>
                      <td className="text-center text-muted fw-bold">{rowIndex + 1}</td>
                      {headers.map((header, colIndex) => (
                        <td key={colIndex}>{row[header] || <span className="text-muted fst-italic">-</span>}</td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : null}
        </div>
        {!loading && data.length > 0 && (
          <div className="card-footer bg-light text-end text-muted small py-3">
            Total de registros: <span className="fw-bold">{data.length}</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default InformeFormulario;
